const shortening={isgd:async function(t){const n="https://is.gd/create.php?format=json&url="+encodeURIComponent(t.trim()),o=await fetch(n),e=await o.json();return e.shorturl},vgd:async function(t){const n="https://v.gd/create.php?format=json&url="+encodeURIComponent(t.trim()),o=await fetch(n),e=await o.json();return e.shorturl},spoome:async function(t){const n="https://spoo.me/",o={method:"POST",headers:{Accept:"application/json","Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams({url:t.trim()})},e=await fetch(n,o),r=await e.json();return r.short_url},trimmlink:async function(t){const n="https://trimm.link/",o=await fetch(n+"shorten",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({link:t})}),e=await o.json(),r=n+(e.word||"");return r}};